SELECT COUNT(DISTINCT LPB.PK) AS QUANTIDADE FROM LATTES_P_PRODBIB LPP JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE JOIN LATTES_PRODBIB LPB ON LPB.PK = LPP.FK_PRODBIB WHERE LOWER(S.GENERO) = LOWER('masculino') AND LOWER(COALESCE(S.SIGLA_CAMPUS, '')) = 'itu' AND LOWER(COALESCE(LPB.TIPO, '')) = 'trabalho em evento' AND LOWER(COALESCE(LPB.NATUREZA, '')) = 'completo' AND TRIM(COALESCE(LPB.ANO, '')) = '2020'